package integration

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"net/http/httptest"
	"testing"

	"go.flipt.io/flipt/internal/server/evaluation"
	"go.flipt.io/flipt/internal/storage"
	"go.flipt.io/flipt/rpc/flipt"
	rpcevaluation "go.flipt.io/flipt/rpc/flipt/evaluation"
	"go.uber.org/zap/zaptest"
	"google.golang.org/grpc"
	"google.golang.org/protobuf/encoding/protojson"
)

// mockStore is a mock implementation of the Storer interface for testing
type mockStore struct {
	flags              map[string]*flipt.Flag
	evaluationRules    map[string][]*storage.EvaluationRule
	evaluationRollouts map[string][]*storage.EvaluationRollout
}

func newMockStore() *mockStore {
	return &mockStore{
		flags:              make(map[string]*flipt.Flag),
		evaluationRules:    make(map[string][]*storage.EvaluationRule),
		evaluationRollouts: make(map[string][]*storage.EvaluationRollout),
	}
}

func (m *mockStore) GetFlag(ctx context.Context, req storage.ResourceRequest) (*flipt.Flag, error) {
	key := fmt.Sprintf("%s:%s", req.Namespace(), req.Key())
	if flag, exists := m.flags[key]; exists {
		return flag, nil
	}
	return nil, fmt.Errorf("flag not found")
}

func (m *mockStore) GetEvaluationRules(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRule, error) {
	key := fmt.Sprintf("%s:%s", req.Namespace(), req.Key())
	if rules, exists := m.evaluationRules[key]; exists {
		return rules, nil
	}
	return []*storage.EvaluationRule{}, nil
}

func (m *mockStore) GetEvaluationDistributions(ctx context.Context, req storage.IDRequest) ([]*storage.EvaluationDistribution, error) {
	return []*storage.EvaluationDistribution{}, nil
}

func (m *mockStore) GetEvaluationRollouts(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRollout, error) {
	key := fmt.Sprintf("%s:%s", req.Namespace(), req.Key())
	if rollouts, exists := m.evaluationRollouts[key]; exists {
		return rollouts, nil
	}
	return []*storage.EvaluationRollout{}, nil
}

// newTestServer creates a test gRPC server with the evaluation service
func newTestServer(store *mockStore) *grpc.Server {
	server := grpc.NewServer()
	logger := zaptest.NewLogger(&testing.T{})
	evalServer := evaluation.New(logger, store)
	evalServer.RegisterGRPC(server)
	return server
}

// TestBooleanFlagEvaluation_Success tests successful boolean flag evaluation
func TestBooleanFlagEvaluation_Success(t *testing.T) {
	store := newMockStore()

	// Register a boolean flag that is enabled
	store.flags["default:feature_enabled"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "feature_enabled",
		Enabled:      true,
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
	}

	// No rollouts means it returns the flag's enabled value
	store.evaluationRollouts["default:feature_enabled"] = []*storage.EvaluationRollout{}

	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, store)

	// Create a test server
	req := &rpcevaluation.EvaluationRequest{
		RequestId:    "test-request-1",
		NamespaceKey: "default",
		FlagKey:      "feature_enabled",
		EntityId:     "user-123",
		Context:      map[string]string{"tier": "premium"},
	}

	resp, err := evalServer.Boolean(context.Background(), req)

	if err != nil {
		t.Fatalf("Boolean evaluation failed: %v", err)
	}

	if !resp.Enabled {
		t.Errorf("expected enabled=true, got enabled=%v", resp.Enabled)
	}

