			{
				RequestId:    "req-3",
				NamespaceKey: "default",
				FlagKey:      "existing_flag",
				EntityId:     "user-batch-3",
			},
			{
				RequestId:    "req-4",
				NamespaceKey: "default",
				FlagKey:      "missing_flag",
				EntityId:     "user-batch-4",
			},
		},
	}

	resp, err := evalServer.Batch(context.Background(), batchReq)

	if err != nil {
		t.Fatalf("Batch evaluation failed: %v", err)
	}

	if len(resp.Responses) != 2 {
		t.Errorf("expected 2 responses, got %d", len(resp.Responses))
	}

	// First response should be successful
	if resp.Responses[0].Type != rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE {
		t.Errorf("expected first response to be BOOLEAN_EVALUATION_RESPONSE_TYPE, got %v", resp.Responses[0].Type)
	}

	// Second response should be an error
	if resp.Responses[1].Type != rpcevaluation.EvaluationResponseType_ERROR_EVALUATION_RESPONSE_TYPE {
		t.Errorf("expected second response to be ERROR_EVALUATION_RESPONSE_TYPE, got %v", resp.Responses[1].Type)
