// TestNamespaceScoping_DifferentNamespaces tests evaluation isolation between namespaces
func TestNamespaceScoping_DifferentNamespaces(t *testing.T) {
	store := newMockStore()

	// Register flags in different namespaces
	store.flags["ns1:flag"] = &flipt.Flag{
		NamespaceKey: "ns1",
		Key:          "flag",
		Enabled:      true,
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
	}

	store.flags["ns2:flag"] = &flipt.Flag{
		NamespaceKey: "ns2",
		Key:          "flag",
		Enabled:      false,
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
	}

	store.evaluationRollouts["ns1:flag"] = []*storage.EvaluationRollout{}
	store.evaluationRollouts["ns2:flag"] = []*storage.EvaluationRollout{}

	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, store)

	// Evaluate in ns1
	req1 := &rpcevaluation.EvaluationRequest{
		RequestId:    "ns1-req",
		NamespaceKey: "ns1",
		FlagKey:      "flag",
		EntityId:     "user-1",
	}

	resp1, err := evalServer.Boolean(context.Background(), req1)
	if err != nil {
		t.Fatalf("Boolean evaluation for ns1 failed: %v", err)
	}

	// Evaluate in ns2
	req2 := &rpcevaluation.EvaluationRequest{
		RequestId:    "ns2-req",
		NamespaceKey: "ns2",
		FlagKey:      "flag",
		EntityId:     "user-2",
	}

	resp2, err := evalServer.Boolean(context.Background(), req2)
	if err != nil {
		t.Fatalf("Boolean evaluation for ns2 failed: %v", err)
	}

	if resp1.Enabled == resp2.Enabled {
		t.Errorf("expected different results for same flag in different namespaces: ns1=%v, ns2=%v", resp1.Enabled, resp2.Enabled)
	}

	if !resp1.Enabled {
		t.Errorf("expected ns1 flag to be enabled, got %v", resp1.Enabled)
	}

	if resp2.Enabled {
		t.Errorf("expected ns2 flag to be disabled, got %v", resp2.Enabled)
	}
}

