// TestBatchEvaluation_FlagNotFound tests batch evaluation with missing flag
func TestBatchEvaluation_FlagNotFound(t *testing.T) {
	store := newMockStore()

	// Only register one flag
	store.flags["default:existing_flag"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "existing_flag",
		Enabled:      true,
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
	}

	store.evaluationRollouts["default:existing_flag"] = []*storage.EvaluationRollout{}

	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, store)

	batchReq := &rpcevaluation.BatchEvaluationRequest{
		RequestId: "batch-2",
		Requests: []*rpcevaluation.EvaluationRequest{
			{
				RequestId:    "req-3",
				NamespaceKey: "default",
				FlagKey:      "existing_flag",
				EntityId:     "user-batch-3",
			},
			{
				RequestId:    "req-4",
				NamespaceKey: "default",
				FlagKey:      "missing_flag",
				EntityId:     "user-batch-4",
			},
		},
	}

	resp, err := evalServer.Batch(context.Background(), batchReq)

	if err != nil {
		t.Fatalf("Batch evaluation failed: %v", err)
	}

	if len(resp.Responses) != 2 {
		t.Errorf("expected 2 responses, got %d", len(resp.Responses))
	}

	// First response should be successful
	if resp.Responses[0].Type != rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE {
		t.Errorf("expected first response to be BOOLEAN_EVALUATION_RESPONSE_TYPE, got %v", resp.Responses[0].Type)
	}

	// Second response should be an error
	if resp.Responses[1].Type != rpcevaluation.EvaluationResponseType_ERROR_EVALUATION_RESPONSE_TYPE {
		t.Errorf("expected second response to be ERROR_EVALUATION_RESPONSE_TYPE, got %v", resp.Responses[1].Type)
	}

	// Verify error response details
	errResp := resp.Responses[1].GetErrorResponse()
	if errResp == nil {
		t.Fatalf("expected error response, got nil")
	}

	if errResp.FlagKey != "missing_flag" {
		t.Errorf("expected error flag_key=missing_flag, got %s", errResp.FlagKey)
	}

	if errResp.Reason != rpcevaluation.ErrorEvaluationReason_NOT_FOUND_ERROR_EVALUATION_REASON {
		t.Errorf("expected error reason=NOT_FOUND_ERROR_EVALUATION_REASON, got %v", errResp.Reason)
	}
}

// TestNamespaceScoping_DifferentNamespaces tests evaluation isolation between namespaces
func TestNamespaceScoping_DifferentNamespaces(t *testing.T) {
	store := newMockStore()

	// Register flags in different namespaces
	store.flags["ns1:flag"] = &flipt.Flag{
		NamespaceKey: "ns1",
		Key:          "flag",
		Enabled:      true,
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
	}

	store.flags["ns2:flag"] = &flipt.Flag{
		NamespaceKey: "ns2",
		Key:          "flag",
		Enabled:      false,
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
	}

	store.evaluationRollouts["ns1:flag"] = []*storage.EvaluationRollout{}
	store.evaluationRollouts["ns2:flag"] = []*storage.EvaluationRollout{}

	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, store)

	// Evaluate in ns1
	req1 := &rpcevaluation.EvaluationRequest{
		RequestId:    "ns1-req",
		NamespaceKey: "ns1",
		FlagKey:      "flag",
		EntityId:     "user-1",
	}

	resp1, err := evalServer.Boolean(context.Background(), req1)
	if err != nil {
		t.Fatalf("Boolean evaluation for ns1 failed: %v", err)
	}

	// Evaluate in ns2
	req2 := &rpcevaluation.EvaluationRequest{
		RequestId:    "ns2-req",
		NamespaceKey: "ns2",
		FlagKey:      "flag",
		EntityId:     "user-2",
	}

	resp2, err := evalServer.Boolean(context.Background(), req2)
	if err != nil {
		t.Fatalf("Boolean evaluation for ns2 failed: %v", err)
	}

	if resp1.Enabled == resp2.Enabled {
		t.Errorf("expected different results for same flag in different namespaces: ns1=%v, ns2=%v", resp1.Enabled, resp2.Enabled)
	}

	if !resp1.Enabled {
		t.Errorf("expected ns1 flag to be enabled, got %v", resp1.Enabled)
	}

	if resp2.Enabled {
		t.Errorf("expected ns2 flag to be disabled, got %v", resp2.Enabled)
	}
}

