		Requests: []*rpcevaluation.EvaluationRequest{
			{
				RequestId:    "json-req-1",
				NamespaceKey: "default",
				FlagKey:      "test_flag",
				EntityId:     "user-json",
			},
		},
	}

	// Marshal to JSON and back to ensure round-trip works
	jsonData, err := protojson.Marshal(batchReq)
	if err != nil {
		t.Fatalf("failed to marshal batch request to JSON: %v", err)
	}

	// Unmarshal back to verify structure
	var unmarshaledReq rpcevaluation.BatchEvaluationRequest
	if err := protojson.Unmarshal(jsonData, &unmarshaledReq); err != nil {
		t.Fatalf("failed to unmarshal batch request from JSON: %v", err)
	}

	if unmarshaledReq.RequestId != "json-batch" {
		t.Errorf("expected request_id=json-batch after round-trip, got %s", unmarshaledReq.RequestId)
	}

	if len(unmarshaledReq.Requests) != 1 {
		t.Errorf("expected 1 request after round-trip, got %d", len(unmarshaledReq.Requests))
	}

	// Evaluate the original batch
	resp, err := evalServer.Batch(context.Background(), batchReq)
	if err != nil {
		t.Fatalf("Batch evaluation failed: %v", err)
	}

	if len(resp.Responses) != 1 {
		t.Errorf("expected 1 response, got %d", len(resp.Responses))
	}
}

