// TestBatchEvaluationRequestID tests that request IDs are preserved in batch responses
func TestBatchEvaluationRequestID(t *testing.T) {
	store := newMockStore()

	store.flags["default:id_test_flag"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "id_test_flag",
		Enabled:      true,
