	if boolResp1.RequestId != "custom-req-id-1" {
		t.Errorf("expected request_id=custom-req-id-1, got %s", boolResp1.RequestId)
	}

	// Check second response ID
	boolResp2 := resp.Responses[1].GetBooleanResponse()
	if boolResp2 == nil {
		t.Fatalf("expected boolean response for second request")
	}
	if boolResp2.RequestId != "custom-req-id-2" {
		t.Errorf("expected request_id=custom-req-id-2, got %s", boolResp2.RequestId)
	}
}

