// TestEvaluationHTTPBoundaries tests HTTP request/response boundaries
func TestEvaluationHTTPBoundaries(t *testing.T) {
	store := newMockStore()

	store.flags["default:http_test"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "http_test",
		Enabled:      true,
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
	}

	store.evaluationRollouts["default:http_test"] = []*storage.EvaluationRollout{}

	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, store)

	// Create a test evaluation request
	req := &rpcevaluation.EvaluationRequest{
		RequestId:    "http-boundary-test",
		NamespaceKey: "default",
		FlagKey:      "http_test",
		EntityId:     "user-http",
		Context: map[string]string{
			"test": "value",
		},
	}

	resp, err := evalServer.Boolean(context.Background(), req)

	if err != nil {
		t.Fatalf("Boolean evaluation failed: %v", err)
	}

	// Verify response can be marshaled to JSON
	respJSON, err := protojson.Marshal(resp)
	if err != nil {
		t.Fatalf("failed to marshal response to JSON: %v", err)
	}

	if len(respJSON) == 0 {
		t.Errorf("marshaled JSON response is empty")
	}

	// Verify we can unmarshal back
	var unmarshaledResp rpcevaluation.BooleanEvaluationResponse
	if err := protojson.Unmarshal(respJSON, &unmarshaledResp); err != nil {
		t.Fatalf("failed to unmarshal response from JSON: %v", err)
	}

	if unmarshaledResp.Enabled != resp.Enabled {
		t.Errorf("expected enabled=%v after round-trip, got %v", resp.Enabled, unmarshaledResp.Enabled)
	}
}

